import { describe, it, expect, beforeEach } from 'vitest';
import { act } from '@testing-library/react';
import { useMyStore } from '@/lib/stores/my-store';

// 공통 리셋: 각 테스트 독립성 보장
beforeEach(() => {
  act(() => {
    useMyStore.getState().resetAll();
  });
});

describe('MyStore 계약', () => {
  it('초기 상태가 올바르다', () => {
    const state = useMyStore.getState();
    expect(state.value).toBeNull();
  });

  it('setValue 액션이 상태를 변경한다', () => {
    act(() => {
      useMyStore.getState().setValue('hello');
    });
    expect(useMyStore.getState().value).toBe('hello');
  });

  it('제거된 필드가 state에 없다 (dead state 검증)', () => {
    const state = useMyStore.getState();
    expect('removedField' in state).toBe(false);
  });
});

import { describe, it, expect, beforeEach, vi } from 'vitest';
import { saveItem, loadItem } from '@/lib/storage';

// localStorage 모킹
const mockStorage: Record<string, string> = {};
Object.defineProperty(globalThis, 'localStorage', {
  value: {
    getItem: (k: string) => mockStorage[k] ?? null,
    setItem: (k: string, v: string) => { mockStorage[k] = v; },
    removeItem: (k: string) => { delete mockStorage[k]; },
  },
  writable: true,
});

beforeEach(() => {
  Object.keys(mockStorage).forEach(k => delete mockStorage[k]);
});

describe('storage utils', () => {
  it('저장 후 불러오기', () => {
    saveItem('key', { a: 1 });
    expect(loadItem('key')).toEqual({ a: 1 });
  });

  it('없는 키는 null 반환', () => {
    expect(loadItem('missing')).toBeNull();
  });
});

