import { describe, it, expect } from 'vitest';
import { act } from '@testing-library/react';
import { useAnalysisStore } from '@/lib/stores/analysis-store';

describe('history restore hygiene', () => {
  it('복원 시 stale AI execution state를 비운다', () => {
    act(() => {
      useAnalysisStore.setState({
        cachedAiRecommendation: { method: { id: 'one-way-anova', name: 'Welch ANOVA', description: '', category: 'anova' }, confidence: 0.9, reasoning: ['stale'], assumptions: [] },
        detectedVariables: { dependentCandidate: 'old_score' },
        suggestedSettings: { welch: true, postHoc: 'games-howell' },
        diagnosticReport: { summary: 'stale' } as never,
      });
      useAnalysisStore.getState().restoreFromHistory({
        analysisPurpose: 'compare',
        selectedMethod: { id: 'two-sample-t', name: 'Independent Samples t-Test', description: '', category: 't-test' },
        variableMapping: null,
        results: null,
        uploadedFileName: 'history.csv',
        currentStep: 2,
        completedSteps: [1],
        analysisOptions: useAnalysisStore.getState().analysisOptions,
      });
    });

    const state = useAnalysisStore.getState();
    expect(state.cachedAiRecommendation).toBeNull();
    expect(state.detectedVariables).toBeNull();
    expect(state.suggestedSettings).toBeNull();
    expect(state.diagnosticReport).toBeNull();
  });
});

import { describe, it, expect } from 'vitest';
import { act } from '@testing-library/react';
import { useAnalysisStore } from '@/lib/stores/analysis-store';

describe('analysis store canonical method ids', () => {
  it('compat alias를 canonical id로 정규화한다', () => {
    act(() => {
      useAnalysisStore.getState().setSelectedMethod({
        id: 't-test',
        name: 'Independent Samples t-Test',
        description: '',
        category: 't-test',
      });
    });

    expect(useAnalysisStore.getState().selectedMethod?.id).toBe('two-sample-t');
  });

  it('persist rehydrate도 canonical id를 유지한다', () => {
    act(() => {
      useAnalysisStore.persist.rehydrate();
    });

    const state = useAnalysisStore.getState();
    expect(state.selectedMethod?.id === 'two-sample-t' || state.selectedMethod?.id === 'one-way-anova' || state.selectedMethod === null).toBe(true);
  });
});

