import { renderHook, act, waitFor } from '@testing-library/react';
import { AppPreferencesProvider } from '@/lib/preferences';
import { useAppPreferences } from '@/hooks/use-app-preferences';

const storageState: Record<string, string> = {};
Object.defineProperty(window, 'localStorage', {
  value: {
    getItem: (key: string) => storageState[key] ?? null,
    setItem: (key: string, value: string) => { storageState[key] = value; },
    removeItem: (key: string) => { delete storageState[key]; },
    clear: () => Object.keys(storageState).forEach((key) => delete storageState[key]),
  },
  writable: true,
});

it('저장된 language/domain을 hydrate하고 변경을 다시 저장한다', async () => {
  storageState['app-language'] = 'en';
  storageState['terminology-domain'] = 'generic';
  const wrapper = ({ children }: { children: React.ReactNode }) => <AppPreferencesProvider>{children}</AppPreferencesProvider>;
  const { result } = renderHook(() => useAppPreferences(), { wrapper });

  await waitFor(() => expect(result.current.currentLanguage).toBe('en'));

  act(() => {
    result.current.setLanguage('ko');
    result.current.setDomain('aquaculture');
  });

  expect(storageState['app-language']).toBe('ko');
  expect(storageState['terminology-domain']).toBe('aquaculture');
});

import { render, type RenderOptions } from '@testing-library/react';
import { AppPreferencesProvider } from '@/lib/preferences';

export function renderWithAppPreferences(
  ui: React.ReactElement,
  {
    language = 'ko',
    domain = 'aquaculture',
    ...options
  }: Omit<RenderOptions, 'wrapper'> & {
    language?: 'ko' | 'en';
    domain?: 'aquaculture' | 'generic';
  } = {},
) {
  return render(ui, {
    wrapper: ({ children }) => (
      <AppPreferencesProvider initialLanguage={language} initialDomain={domain}>
        {children}
      </AppPreferencesProvider>
    ),
    ...options,
  });
}

