// === Worker 구성 ===
// Worker 1: scipy만 (가벼움) - normality_test, descriptive_stats, outlier_detection
// Worker 2: scipy + statsmodels (중간) - t-tests, chi-square, correlation
// Worker 3: scikit-learn (무거움) - nonparametric + ANOVA + post-hoc
// Worker 4: scikit-learn (무거움) - regression + PCA + factor + cluster

// Worker 로딩 시간 차이 (scikit-learn 여부)
//
// Worker 1: scipy only       → ~2초  (기본 통계)
// Worker 2: scipy+statsmodels → ~3초  (가설 검정)
// Worker 3: +scikit-learn    → ~8초  (비모수 + ANOVA)
// Worker 4: +scikit-learn    → ~8초  (회귀 + 고급)
//
// 최적화 원칙:
// - 간단한 통계 (평균, 정규성, 이상치) → Worker 1
// - 가설 검정 (t-test, chi-square)    → Worker 2
// - 비모수 + ANOVA                    → Worker 3
// - 회귀 + 고급 분석                  → Worker 4

// ✅ 올바른 Worker 선택
await this.ensureWorker1Loaded()  // scipy만 필요한 함수
return this.callWorkerMethod(1, 'descriptive_stats', { data })

// ❌ 잘못된 Worker 선택 (불필요하게 무거운 Worker 사용)
await this.ensureWorker4Loaded()  // scikit-learn 불필요한데 Worker 4 사용
return this.callWorkerMethod(4, 'descriptive_stats', { data })

