// === StatisticalExecutor (Thin Dispatcher) ===
// 파일: lib/services/statistical-executor.ts
// 역할: UI와 Python Worker 사이의 라우팅 + 데이터 준비

class StatisticalExecutor {
  static getInstance(): StatisticalExecutor

  async executeMethod(
    method: StatisticalMethod,
    data: any[],
    variables: {
      dependent?: string[]
      independent?: string[]
      group?: string
      time?: string
      covariate?: string[]
      within?: string[]
      between?: string[]
    }
  ): Promise<StatisticalExecutorResult>

  // 1. prepareData() → PreparedData 생성
  // 2. switch(method.category) → handler 함수 호출
  switch (method.category) {
    case 'descriptive':   → handleDescriptive(method, data)
    case 't-test':        → handleTTest(method, data)
    case 'anova':         → handleANOVA(method, data)
    case 'regression':    → handleRegression(method, data)
    case 'correlation':   → handleCorrelation(method, data)
    case 'nonparametric': → handleNonparametric(method, data)
    case 'chi-square':    → handleChiSquare(method, data)
    case 'multivariate':  → handleMultivariate(method, data)
    case 'timeseries':    → handleTimeSeries(method, data)
    case 'psychometrics': → handleReliability(method, data)
    case 'survival':      → handleSurvival(method, data)
    case 'design':        → handleDesign(method, data)
  }
}

