// === PyodideCoreService ===
// 파일: lib/services/pyodide/core/pyodide-core.service.ts
// 역할: Pyodide 인스턴스 관리 + Worker 로딩 + 메서드 호출

class PyodideCoreService {
  // Singleton 패턴
  private static instance: PyodideCoreService

  // 핵심 메서드: Worker 함수 호출
  async callWorkerMethod<T>(
    workerNum: number,           // Worker 번호 (1-4)
    funcName: string,            // Python 함수명 (snake_case)
    params: Record<string, any>  // 파라미터 객체
  ): Promise<T> {
    // 1. Worker 로딩 확인
    await this.ensureWorkerLoaded(workerNum)

    // 2. Python 함수 호출
    const pythonCode = `
      import json
      result = ${funcName}(**${JSON.stringify(params)})
      json.dumps(result)
    `

    // 3. 결과 파싱 및 반환
    const result = await this.pyodide.runPythonAsync(pythonCode)
    return JSON.parse(result) as T
  }

  // Worker 로딩 (Lazy Loading)
  private async ensureWorkerLoaded(workerNum: number) {
    if (this.loadedWorkers.has(workerNum)) return

    const workerCode = await fetch(`/workers/python/worker${workerNum}-*.py`)
    await this.pyodide.runPythonAsync(workerCode)
    this.loadedWorkers.add(workerNum)
  }
}

