interface StatisticalExecutorResult {
  // 1. 메타데이터
  metadata: {
    method: string           // 메서드 ID (예: 'two-sample-t')
    methodName: string       // 표시명 (예: '독립표본 t-검정')
    timestamp: string        // ISO 8601 (예: '2025-11-27T12:00:00Z')
    duration: number         // 실행 시간 (초)
    dataInfo: {
      totalN: number         // 총 표본 수
      missingRemoved: number // 제거된 결측값 수
      groups?: number        // 그룹 수 (해당 시)
    }
  }

  // 2. 주 결과
  mainResults: {
    statistic: number        // 검정통계량 (t, F, χ², r 등)
    pvalue: number           // 유의확률
    df?: number              // 자유도
    significant: boolean     // 유의 여부 (p < 0.05)
    interpretation?: string  // 결과 해석 문장
  }

  // 3. 부가 정보
  additionalInfo: {
    effectSize?: {           // 효과크기
      type: string           // "Cohen's d", "eta-squared", "R²" 등
      value: number
      interpretation: string // "작은 효과", "중간 효과" 등
    }
    confidenceInterval?: {   // 신뢰구간
      level: number          // 95
      lower: number
      upper: number
    }
    assumptions?: {          // 가정 검정 결과
      passed: boolean
      details: any[]
    }
    postHoc?: any            // 사후검정 결과 (ANOVA)
  }

  // 4. 시각화 데이터
  visualizationData?: {
    type: string             // 'boxplot', 'histogram', 'scatter' 등
    data: any                // 차트 렌더링용 데이터
  }

  // 5. 원시 결과 (디버깅용)
  rawResults?: any           // Python Worker 원본 반환값
}

