import { readFileSync } from 'fs'
import { getAllMethods, WorkerNumber } from '@/lib/constants/methods-registry.types'

function extractPythonFunctions(workerNum: WorkerNumber): string[] {
  const filePath = `public/workers/python/worker${workerNum}-*.py`
  const content = readFileSync(filePath, 'utf8')
  const pattern = /^def ([a-z][a-z0-9_]*)\(/gm
  const functions: string[] = []
  let match
  while ((match = pattern.exec(content)) !== null) {
    functions.push(match[1])
  }
  return functions
}

