import { describe, it, expect } from 'vitest';
import { applyPatches } from '@/lib/graph-studio/chart-spec-utils';
import type { ChartSpec } from '@/types/graph-studio';

// 최소 spec 픽스처
const baseSpec: ChartSpec = { /* ... */ };

describe('applyPatches — RFC 6901/6902 준수', () => {
  it('~1 → /, ~0 → ~ 순서대로 언이스케이프', () => {
    const spec = { ...baseSpec, annotations: [{ id: 'a/b~c', text: 'old' }] };
    const result = applyPatches(spec, [{
      op: 'replace',
      path: '/annotations/0/text',
      value: 'new',
    }]);
    expect(result.annotations?.[0].text).toBe('new');
  });

  it('add — 배열 인덱스 0에 삽입 (splice)', () => {
    const spec = { ...baseSpec, annotations: [{ id: 'b', text: 'second' }] };
    const result = applyPatches(spec, [{
      op: 'add',
      path: '/annotations/0',
      value: { id: 'a', text: 'first' },
    }]);
    expect(result.annotations?.[0].id).toBe('a');
    expect(result.annotations?.[1].id).toBe('b');
  });

  it('add — "-" 인덱스로 append', () => {
    const spec = { ...baseSpec, annotations: [{ id: 'a', text: 'first' }] };
    const result = applyPatches(spec, [{
      op: 'add',
      path: '/annotations/-',
      value: { id: 'b', text: 'second' },
    }]);
    expect(result.annotations).toHaveLength(2);
    expect(result.annotations?.[1].id).toBe('b');
  });

  it('replace — 범위 초과 인덱스는 no-op (sparse array 방지)', () => {
    // JavaScript arr[999] = value → sparse array(length=1000) 버그 방지
    const spec = { ...baseSpec, annotations: [] };
    const result = applyPatches(spec, [{
      op: 'replace',
      path: '/annotations/999',
      value: { id: 'x', text: 'ghost' },
    }]);
    expect(result.annotations).toHaveLength(0);
  });

