import { describe, it, expect, vi, beforeEach, afterEach } from 'vitest';
import { downloadChart } from '@/lib/graph-studio/export-utils';
import type { EChartsType } from 'echarts';

function makeMockECharts(): EChartsType {
  return {
    getDataURL: vi.fn().mockReturnValue('data:image/png;base64,abc'),
    getSvgDataURL: vi.fn().mockReturnValue('data:image/svg+xml;base64,xyz'),
  } as unknown as EChartsType;
}

describe('downloadChart', () => {
  let mockLink: { href: string; download: string; click: ReturnType<typeof vi.fn> };

  beforeEach(() => {
    mockLink = { href: '', download: '', click: vi.fn() };
    vi.spyOn(document, 'createElement').mockReturnValue(mockLink as unknown as HTMLAnchorElement);
    vi.spyOn(document.body, 'appendChild').mockReturnValue(mockLink as unknown as Node);
    vi.spyOn(document.body, 'removeChild').mockReturnValue(mockLink as unknown as Node);
  });

  afterEach(() => { vi.restoreAllMocks(); });

  it('null 인스턴스 → 조기 반환 (DOM 접근 없음)', () => {
    downloadChart(null, { format: 'png', dpi: 96 }, 'chart');
    expect(document.createElement).not.toHaveBeenCalled();
  });

  it('PNG: getDataURL 호출 + 96dpi → pixelRatio=1', () => {
    const ec = makeMockECharts();
    downloadChart(ec, { format: 'png', dpi: 96 }, 'result');
    expect(ec.getDataURL).toHaveBeenCalledWith({ type: 'png', pixelRatio: 1, backgroundColor: '#ffffff' });
    expect(mockLink.download).toBe('result.png');
  });

  it('SVG: getSvgDataURL 호출 + getDataURL 미호출', () => {
    const ec = makeMockECharts();
    downloadChart(ec, { format: 'svg', dpi: 96 }, 'fig');
    expect(ec.getSvgDataURL).toHaveBeenCalled();
    expect(ec.getDataURL).not.toHaveBeenCalled();
    expect(mockLink.download).toBe('fig.svg');
  });

  it('Firefox 호환: body.appendChild → click → body.removeChild 순서', () => {
    const order: string[] = [];
    vi.spyOn(document.body, 'appendChild').mockImplementation(() => { order.push('append'); return mockLink as unknown as Node; });
    vi.spyOn(document.body, 'removeChild').mockImplementation(() => { order.push('remove'); return mockLink as unknown as Node; });
    mockLink.click = vi.fn().mockImplementation(() => { order.push('click'); });
    downloadChart(makeMockECharts(), { format: 'png', dpi: 96 }, 'chart');
    expect(order).toEqual(['append', 'click', 'remove']);
  });

  it('파일명 undefined → "chart" 폴백', () => {
    downloadChart(makeMockECharts(), { format: 'png', dpi: 96 }, undefined);
    expect(mockLink.download).toBe('chart.png');
  });
});

