function createSim(initial = '0.5') {
  let value = initial
  let source: 'manual' | 'auto' = 'manual'
  let field1 = '', field2 = ''
  function applyEffect() {
    if (source !== 'auto') return
    const v1 = parseFloat(field1), v2 = parseFloat(field2)
    if (isFinite(v1) && isFinite(v2)) value = (v1 + v2).toFixed(3)
  }
  return {
    handleManual: (v: string) => { value = v; source = 'manual' },
    handleField1: (v: string) => { field1 = v; source = 'auto'; applyEffect() },
    handleField2: (v: string) => { field2 = v; source = 'auto'; applyEffect() },
    get value() { return value },
    get source() { return source },
  }
}

test('자동 계산 후 수동 입력 유지', () => {
  const sim = createSim()
  sim.handleField1('10'); sim.handleField2('20')
  expect(sim.source).toBe('auto')
  sim.handleManual('0.5')    // manual override
  expect(sim.value).toBe('0.5')
  expect(sim.source).toBe('manual')
  // no field change → value stays
  expect(sim.value).toBe('0.5')
})

