  localStorage.setItem(STORAGE_KEYS.ui.sidebar, 'collapsed');
});

it('shows only the active tooltip while collapsed', async () => {
  const user = userEvent.setup();
  const { container } = render(<AppSidebar />);

  const bioToolsLink = container.querySelector('a[href="/bio-tools"]') as HTMLElement;
  const graphStudioLink = container.querySelector('a[href="/graph-studio"]') as HTMLElement;

  await user.hover(bioToolsLink);

  const firstTooltip = await screen.findByRole('tooltip');
  expect(within(firstTooltip).getByText('Bio-Tools')).toBeInTheDocument();

  await user.hover(firstTooltip);
  await user.unhover(bioToolsLink);
  await user.hover(graphStudioLink);

  await waitFor(() => {
    const tooltips = screen.getAllByRole('tooltip');
    expect(tooltips).toHaveLength(1);
    expect(within(tooltips[0] as HTMLElement).getByText('Graph Studio')).toBeInTheDocument();
  });
});

import { test, expect } from '@playwright/test';
import { readAnalysisHistoryCount, resetAnalysisHistoryStore, seedAnalysisHistoryRecord, readStoredHistorySnapshot } from '../helpers/history-helpers';

test.beforeEach(async ({ page }) => {
  await page.addInitScript(() => {
    sessionStorage.clear();
    localStorage.removeItem('analysis-history-pinned');
  });
});

test('seeded history can be renamed and persists the new label', async ({ page }) => {
  await page.goto('/');
  await resetAnalysisHistoryStore(page);
  await seedAnalysisHistoryRecord(page, buildSeededRecord({ id: 'history-rename-seed' }));
  await page.goto('/');

  await expect.poll(async () => readAnalysisHistoryCount(page)).toBe(1);
  await page.locator('[data-testid="analysis-history-more-actions-history-rename-seed"]').click();
  await page.locator('[data-testid="analysis-history-rename-action-history-rename-seed"]').click();
  await page.locator('[data-testid="analysis-history-rename-input"]').fill('Renamed');
  await page.locator('[data-testid="analysis-history-rename-save"]').click();

  const snapshot = await readStoredHistorySnapshot(page, 'history-rename-seed');
  expect(snapshot?.name).toBe('Renamed');
});

