  // 렌더링 검증
  // 입력 검증
  // 제출 검증
  // 에러 검증
});

// ✅ Good: 각 동작을 별도 테스트로 분리
it('폼이 정상 렌더링되어야 함', () => { ... });
it('입력 필드가 정상 동작해야 함', () => { ... });
it('제출 시 데이터가 전송되어야 함', () => { ... });
it('검증 실패 시 에러 메시지가 표시되어야 함', () => { ... });

// ❌ Bad: 비동기 대기 없이 즉시 검증
it('데이터 로딩 후 표시', () => {
  render(<MyComponent />);
  expect(screen.getByText('Data')).toBeInTheDocument();  // 실패!
});

// ✅ Good: waitFor로 비동기 대기
it('데이터 로딩 후 표시', async () => {
  render(<MyComponent />);

  await waitFor(() => {
    expect(screen.getByText('Data')).toBeInTheDocument();
  });
});

// ✅ Better: findBy 사용 (자동 대기)
it('데이터 로딩 후 표시', async () => {
  render(<MyComponent />);

  const data = await screen.findByText('Data');
  expect(data).toBeInTheDocument();
});

