import { describe, expect, it } from 'vitest';
import { getDefaultSetupFieldSelection } from '@/lib/graph-studio/editor-actions';

const columns = [
  { name: 'species', type: 'nominal', uniqueCount: 3, sampleValues: ['A', 'B'], hasNull: false },
  { name: 'length_cm', type: 'quantitative', uniqueCount: 3, sampleValues: ['10', '20'], hasNull: false },
  { name: 'weight_g', type: 'quantitative', uniqueCount: 3, sampleValues: ['100', '200'], hasNull: false },
];

describe('preferredXY defaults', () => {
  it('scatter에서는 preferredXY를 그대로 사용한다', () => {
    expect(getDefaultSetupFieldSelection(columns, 'scatter', { x: 'length_cm', y: 'weight_g' })).toEqual({
      xField: 'length_cm',
      yField: 'weight_g',
      colorField: 'none',
    });
  });

  it('bar 계약과 맞지 않으면 nominal x + quantitative y로 fallback한다', () => {
    expect(getDefaultSetupFieldSelection(columns, 'bar', { x: 'length_cm', y: 'weight_g' })).toEqual({
      xField: 'species',
      yField: 'weight_g',
      colorField: 'none',
    });
  });
});

import { chartSpecToECharts } from '@/lib/graph-studio/echarts-converter';
import type { ChartSpec } from '@/types/graph-studio';

function makeKmSpec(overrides: Partial<ChartSpec> = {}): ChartSpec {
  return {
    chartType: 'km-curve',
    xField: 'time', yField: 'survival', colorField: 'group',
    title: 'KM Curve', ...overrides,
  };
}

const kmRows = [
  { time: 0, survival: 1.0, ciLo: 1.0, ciHi: 1.0, group: 'A' },
  { time: 12, survival: 0.8, ciLo: 0.6, ciHi: 0.95, group: 'A' },
];

test('km-curve: step line + CI areaStyle', () => {
  const option = chartSpecToECharts(makeKmSpec(), kmRows) as Record<string, unknown>;
  const series = option.series as Record<string, unknown>[];
  const mainLine = series.find(s => s.step === 'end');
  expect(mainLine).toBeDefined();
  const area = series.find(s => (s.areaStyle as Record<string, unknown>)?.opacity > 0);
  expect(area).toBeDefined();
});

test('roc-curve: AUC graphic text 포함', () => {
  const rocSpec: ChartSpec = { chartType: 'roc-curve', xField: 'fpr', yField: 'tpr', title: 'ROC' };
  const rocRows = [{ fpr: 0.0, tpr: 0.0 }, { fpr: 0.3, tpr: 0.8 }, { fpr: 1.0, tpr: 1.0 }];
  const option = chartSpecToECharts(rocSpec, rocRows) as Record<string, unknown>;
  const graphic = option.graphic as unknown[];
  expect(Array.isArray(graphic)).toBe(true);
  const aucText = (graphic as Record<string, unknown>[]).find(g => String(g.type) === 'text');
  expect(aucText).toBeDefined();
});

import { describe, it, expect } from 'vitest';

// Python Worker가 반환하는 camelCase 결과 형태
interface Worker2AncovaResult {
  mainEffect: { fStatistic: number; pValue: number; df1: number; df2: number };
  postHoc?: Array<{ group1: string; group2: string; meanDiff: number; pValue: number; pAdjusted?: number; significant: boolean }>;
  effectSize?: { etaSquared: number; label: string };
  adjustedMeans?: Array<{ group: string; adjustedMean: number; se: number }>;
  missingRemoved?: number;
}

function mapAncovaResult(raw: Worker2AncovaResult) {
  return {
    statistic: raw.mainEffect.fStatistic,
    pValue: raw.mainEffect.pValue,
    df: [raw.mainEffect.df1, raw.mainEffect.df2] as [number, number],
    postHoc: raw.postHoc?.map(p => ({
      group1: p.group1, group2: p.group2, meanDiff: p.meanDiff,
      pvalue: p.pValue, pvalueAdjusted: p.pAdjusted, significant: p.significant,
    })),
    missingRemoved: raw.missingRemoved ?? 0,
  };
}

describe('ANCOVA Worker2 결과 매핑', () => {
  it('df가 [df1, df2] 튜플로 보존된다', () => {
    const raw: Worker2AncovaResult = { mainEffect: { fStatistic: 5.2, pValue: 0.03, df1: 1, df2: 28 } };
    const mapped = mapAncovaResult(raw);
    expect(mapped.df).toEqual([1, 28]);
  });

  it('null 그룹 필터링 후 missingRemoved 계산', () => {
    const raw: Worker2AncovaResult = { mainEffect: { fStatistic: 3.1, pValue: 0.09, df1: 1, df2: 15 }, missingRemoved: 3 };
    const mapped = mapAncovaResult(raw);
    expect(mapped.missingRemoved).toBe(3);
  });
});

